toolUseResult.originalFile:
// Types

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: 'quote';
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: 'claim';
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioOutput {
  results: StepResult[];
}

// Item catalog

const MAIN_ITEMS: Record<string, { value: number; premium: number }> = {
  sword:  { value: 1000, premium: 100 },
  amulet: { value: 600,  premium: 60 },
  staff:  { value: 800,  premium: 80 },
  potion: { value: 400,  premium: 40 },
};

const COMPONENT_TYPES = new Set(['rune', 'moonstone']);

const COMPONENT_VALUE = 250;
const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const PROCESSING_FEE = 5;
const DEDUCTIBLE_PER_DAMAGE = 100;

function isComponent(type: string): boolean {
  return COMPONENT_TYPES.has(type);
}

function isKnownType(type: string): boolean {
  return type in MAIN_ITEMS || isComponent(type);
}

function itemInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].value;
  if (isComponent(item.type)) return COMPONENT_VALUE;
  throw new Error(`Unknown item type: ${item.type}`);
}

// Premium calculation

interface ItemBase {
  item: Item;
  basePremium: number;
}

function itemBasePremiums(items: Item[]): ItemBase[] {
  // Main items
  const mains: ItemBase[] = [];
  // Components grouped by type
  const componentsByType: Record<string, Item[]> = {};

  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
    if (item.type in MAIN_ITEMS) {
      mains.push({ item, basePremium: MAIN_ITEMS[item.type].premium });
    } else {
      if (!componentsByType[item.type]) componentsByType[item.type] = [];
      componentsByType[item.type].push(item);
    }
  }

  const componentBases: ItemBase[] = [];
  for (const type of Object.keys(componentsByType)) {
    const group = componentsByType[type];
    const count = group.length;
    // Compute the group's total base premium using blocks of 3
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count % COMPONENT_BLOCK_SIZE;
    let totalGroupBase = blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_PREMIUM;
    // Distribute equally across the components (each component still has its own
    // modifiers attached, but the block discount affects the *group* total).
    // For the purposes of item-specific modifiers, treat each component's
    // basePremium as its share of the group total.
    const perItem = totalGroupBase / count;
    for (const it of group) {
      componentBases.push({ item: it, basePremium: perItem });
    }
  }

  return [...mains, ...componentBases];
}

function itemSurcharge(base: ItemBase): number {
  let surcharge = 0;
  const item = base.item;
  if (item.cursed) {
    surcharge += base.basePremium * 0.5;
  }
  if (item.enchantment !== undefined && item.enchantment >= 5) {
    surcharge += base.basePremium * 0.3;
  }
  return surcharge;
}

function roundUp(n: number): number {
  return Math.ceil(n);
}

function roundDown(n: number): number {
  return Math.floor(n);
}

export function computePremium(items: Item[], customer: Customer, isFollowUpContract: boolean): number {
  const bases = itemBasePremiums(items);

  const policyBase = bases.reduce((sum, b) => sum + b.basePremium, 0);
  const itemSurcharges = bases.reduce((sum, b) => sum + itemSurcharge(b), 0);

  // Policy-wide modifiers apply to policy base premium
  let policyMods = 0;
  if (customer.yearsWithMHPCO >= 2) {
    policyMods -= policyBase * 0.2; // loyalty discount
  }
  // First insurance surcharge: applies per item in quote (each item is a first insurance)
  // Per the spec, the surcharge is 10% — but the integration examples show it as a flat
  // application against the policy base. Re-reading:
  //   "A first insurance carries a 10 % initial assessment surcharge."
  //   In the integration example (newcomer cursed sword): 100 base + 50 curse + 10 first
  //   insurance = 160. So 10% of 100 (base of that item, "first insurance" per item).
  // Each item in the quote is treated as a "first insurance" per the second integration ex.
  const firstInsuranceSurcharge = bases.reduce((sum, b) => sum + b.basePremium * 0.1, 0);

  // Follow-up contract discount: 15% on each contract after the first
  let followUp = 0;
  if (isFollowUpContract) {
    followUp = -policyBase * 0.15;
  }

  const beforeFee = policyBase + itemSurcharges + policyMods + firstInsuranceSurcharge + followUp;
  const total = beforeFee + PROCESSING_FEE;

  return roundUp(total);
}

// Claim processing

interface Policy {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

export function buildPolicy(items: Item[]): Policy {
  // Validate all known
  for (const it of items) {
    if (!isKnownType(it.type)) throw new Error(`Unknown item type: ${it.type}`);
  }
  const insuranceSum = items.reduce((sum, it) => sum + itemInsuranceValue(it), 0);
  const cap = insuranceSum * 2;
  return { items, insuranceSum, cap, remainingCap: cap };
}

function payoutForDamage(item: Item, amount: number): number {
  let reimbursable = amount;
  const enchantment = item.enchantment ?? 0;
  const isDragon = item.material === 'dragon';
  const isHighlyEnchanted = enchantment >= 8;

  if (isHighlyEnchanted) {
    // High-enchantment 50% rule wins even when material is dragon
    reimbursable = amount * 0.5;
  } else if (isDragon) {
    reimbursable = amount;
  } else {
    reimbursable = amount;
  }
  const afterDeductible = reimbursable - DEDUCTIBLE_PER_DAMAGE;
  return Math.max(0, afterDeductible);
}

export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
  // Validate damages: count of each type cannot exceed policy items of that type
  const policyCountsByType: Record<string, number> = {};
  for (const it of policy.items) {
    policyCountsByType[it.type] = (policyCountsByType[it.type] ?? 0) + 1;
  }
  const damageCountsByType: Record<string, number> = {};
  for (const d of incident.damages) {
    if (d.amount < 0) throw new Error(`Negative damage amount: ${d.amount}`);
    if (!isKnownType(d.itemType)) throw new Error(`Unknown damage item type: ${d.itemType}`);
    damageCountsByType[d.itemType] = (damageCountsByType[d.itemType] ?? 0) + 1;
  }
  for (const type of Object.keys(damageCountsByType)) {
    if ((policyCountsByType[type] ?? 0) < damageCountsByType[type]) {
      throw new Error(`Damage references item type not in policy or exceeds count: ${type}`);
    }
  }

  // Match each damage to an available item of that type (first match)
  // For simplicity, match in order; if there are multiple items of same type with
  // different properties (e.g. dragon-material), match each damage to a distinct item.
  const itemsByType: Record<string, Item[]> = {};
  for (const it of policy.items) {
    if (!itemsByType[it.type]) itemsByType[it.type] = [];
    itemsByType[it.type].push(it);
  }
  // Make working copies (we'll pop as we use them)
  const available: Record<string, Item[]> = {};
  for (const k of Object.keys(itemsByType)) {
    available[k] = [...itemsByType[k]];
  }

  let total = 0;
  for (const d of incident.damages) {
    const candidates = available[d.itemType];
    if (!candidates || candidates.length === 0) {
      throw new Error(`No item available for damage: ${d.itemType}`);
    }
    const item = candidates.shift()!;
    const p = payoutForDamage(item, d.amount);
    total += p;
  }

  // Cap to remainingCap
  let payout = total;
  if (payout > policy.remainingCap) {
    payout = policy.remainingCap;
  }
  // Round down (in favor of MHPCO)
  payout = roundDown(payout);
  policy.remainingCap = policy.remainingCap - payout;
  if (policy.remainingCap < 0) policy.remainingCap = 0;
  return { payout, remainingCap: policy.remainingCap };
}

// Scenario runner

export function runScenario(scenario: Scenario): ScenarioOutput {
  const results: StepResult[] = [];
  const policies: Record<number, Policy> = {};
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === 'quote') {
      const isFollowUp = quoteCount >= 1;
      const premium = computePremium(step.items, scenario.customer, isFollowUp);
      // Build policy and store
      const policy = buildPolicy(step.items);
      policies[i] = policy;
      results.push({ premium });
      quoteCount++;
    } else {
      const policy = policies[step.policy];
      if (!policy) throw new Error(`No policy at step ${step.policy}`);
      const r = processClaim(policy, step.incident);
      results.push(r);
    }
  }
  return { results };
}

